// Loop through fuelEntries array and create one item per fuel entry with the log ID
const items = [];

for (const item of $input.all()) {
  const logId = item.json.body.id;
  const fuelEntries = item.json.body.fuelEntries || [];

  for (const fuelEntry of fuelEntries) {
    items.push({
      json: {
        id: logId,
        machineryHours: fuelEntry.machineryHours,
        litres: fuelEntry.litres,
        attendant: fuelEntry.attendant
      }
    });
  }
}

return items;

// Loop through breakdowns array and create one item per breakdown with the log ID
const items = [];

for (const item of $input.all()) {
  const logId = item.json.body.id;
  const breakdowns = item.json.body.breakdowns || [];

  for (const breakdown of breakdowns) {
    items.push({
      json: {
        id: logId,
        breakdown: breakdown,
        type: breakdown.type,
        startTime: breakdown.startTime,
        endTime: breakdown.endTime,
        totalDowntime: breakdown.totalDowntime
      }
    });
  }
}

return items;
